INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES ("", 21, 1010806023, "", 0, "vo_dsb_6002", 0, "vo_dsb_1010806", "", "", 1010806);
INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES (0, 11, 1010806024, 1, 10, "ブラック労働のストレスからの食欲！\n食欲からのぜい肉！\nこの私腹を肥やすのは却下ですわ！\nすっきりごっそり清算しますわよ～！！", 1, 2, 0.2, 0, 1010806);
INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES ("", 91, 1010806025, "", "", "", "", 0, "", "", 1010806);
