INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES (0, 11, 1010806034, 1, 10, "ええ、ええ！　もちろんですわ！\nそれにしても……短時間で\nこれほどの温泉が用意できるとは。\nさすがは『隻眼の悪魔』ですわね？", 1, 2, 0.2, 0, 1010806);
INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES ("", 91, 1010806035, "", "", "", "", 0, "", "", 1010806);
