INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES (0, 11, 1010806092, 1, 10, "ああ、心配しないで。\nちゃんと脂肪燃焼効果はあるから。\nちなみに私もよく入ってるし。\n健康に害はないわよ。", 1, 1, 0.2, 0, 1010806);
INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES ("", 91, 1010806093, "", "", "", "", 0, "", "", 1010806);
