INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES (0, 11, 1010806097, 1, 10, "だからって……ああっ！！\n目っ！　刺激が目に！　来ましたわ！\nくうう……ですが報酬を払った以上\n最大限利用しませんと～ッ！！！", 1, 2, 0.2, 0, 1010806);
INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES ("", 91, 1010806098, "", "", "", "", 0, "", "", 1010806);
