INSERT INTO `v1_5914ebf51f8d06b6f48fe8bc530d18394af90e4d1836212c3aedd6a08aacf1b3` VALUES (0, 11, 1010806101, 1, 10, "途中で投げ出さないなんて\nさすがは商売人ね……\nこの覚悟の決まった損得勘定、\n伊達じゃないわ……！", 1, 1, 0.2, 0, 1010806);
